		expect(evidence?.classifierDiagnostics?.failedAttempts[0]?.rawOutput?.available).toBe(
			true,
		);
		expect(
			evidence?.classifierDiagnostics?.failedAttempts[0]?.rawOutput?.preview?.length,
		).toBeLessThanOrEqual(320);
